import React, { useState, useEffect } from 'react';
import Select from 'react-select';
import './AddPurchase.css';

const AddPurchase = ({ handleAdd, locations, vendors, materials }) => {
  const initialPurchaseState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    price: '',
    vendor: '',
    vendorname: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);

  useEffect(() => {
    const fetchMaterialChanges = async () => {
      if (newPurchase.materialid) {
        try {
          const [materialchangesrespond, materialresponse] = await Promise.all([
            fetch(`http://localhost:8081/materialchangesAPI/${newPurchase.materialid}`).then((response) => response.json()),
            fetch(`http://localhost:8081/materiallist/${newPurchase.materialid}`).then((response) => response.json()),
          ]);

          if (materialchangesrespond && materialchangesrespond.price && materialchangesrespond.vendor) {
            const selectedVendor = vendors.find((vendor) => vendor.vendorid === materialchangesrespond.vendor);
            const selectedMaterial = materials.find((mat) => mat.matid === materialresponse.materialid);
            if (selectedVendor) {
              setNewPurchase((prevPurchase) => ({
                ...prevPurchase,
                price: materialchangesrespond.price,
                vendor: materialchangesrespond.vendor,
                vendorname: selectedVendor.name,
                materialname: selectedMaterial.name,
              }));
            } else {
              setNewPurchase((prevPurchase) => ({
                ...prevPurchase,
                price: '',
                vendor: '',
                vendorname: '',
              }));
            }
          } else {
            // If no data available for the selected materialid, update the price and reset vendor to empty string
            setNewPurchase((prevPurchase) => ({
              ...prevPurchase,
              price: '',
              vendor: '',
              vendorname: '',
            }));
          }
        } catch (error) {
          console.error('Error fetching material changes:', error);
        }
      } else {
        // Clear the default values if no materialid is selected
        setNewPurchase((prevPurchase) => ({
          ...prevPurchase,
          price: '',
          vendor: '',
          vendorname: '',
        }));
      }
    };

    fetchMaterialChanges();
  }, [newPurchase.materialid, vendors, materials]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase({
      ...newPurchase,
      [name]: value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Convert the selected vendor name back to vendor ID before submitting to the API
    const selectedVendor = vendors.find((vendor) => vendor.name === newPurchase.vendorname);
    if (selectedVendor) {
      setNewPurchase((prevPurchase) => ({
        ...prevPurchase,
        vendor: selectedVendor.vendorid,
      }));
    }

    handleAdd(newPurchase);
    setNewPurchase(initialPurchaseState);
  };

  const vendorOptions = vendors.map((vendor) => ({
    value: vendor.name,
    label: vendor.name,
  }));

  return (
    <form onSubmit={handleSubmit} className='add-purchase-form'>
      <div>
        <label>Location:</label>
        <select name="location" value={newPurchase.location} onChange={handleChange}>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={newPurchase.materialid} onChange={handleChange} />
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={newPurchase.materialname} readOnly />
      </div>
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={newPurchase.quantity} onChange={handleChange} />
      </div>
      <div>
        <label>Price:</label>
        <input
          type="text"
          name="price"
          value={newPurchase.price} 
          onChange={handleChange}
        />
      </div>
      <div>
        <label>Vendor:</label>
        <Select
          options={vendorOptions}
          value={vendorOptions.find((option) => option.label === newPurchase.vendorname)} // Find the vendor option based on the selected vendor name
          onChange={handleVendorChange}
          placeholder="Select a Vendor"
          isSearchable // Enable search functionality
        />
      </div>
      <button type="submit" className="add_purchase_btn">Add Purchase</button>
    </form>
  );
};

export default AddPurchase;
